Python code — database connection pooling:
import psycopg2
from psycopg2 import pool

class DatabasePool:
    def __init__(self, dsn: str, min_conn: int = 2, max_conn: int = 10):
        self.pool = psycopg2.pool.ThreadedConnectionPool(min_conn, max_conn, dsn)

    def execute(self, query: str, params=None):
        conn = self.pool.getconn()
        try:
            with conn.cursor() as cur:
                cur.execute(query, params)
                conn.commit()
                return cur.fetchall()
        finally:
            self.pool.putconn(conn)

Go code — HTTP middleware for request logging:
func LoggingMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		rw := &responseWriter{ResponseWriter: w, statusCode: http.StatusOK}
		next.ServeHTTP(rw, r)
		log.Printf("%s %s %d %s",
			r.Method, r.RequestURI, rw.statusCode, time.Since(start))
	})
}

